import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

function ViewApplications() {
  const navigate = useNavigate();
  const [apps, setApps] = useState([]);

  const loggedUser =
    JSON.parse(localStorage.getItem("loggedInUser")) || {};

  useEffect(() => {
    const storedApps =
      JSON.parse(localStorage.getItem("applications")) || [];

    setApps(storedApps);
  }, []);

  return (
    <div style={{ marginTop: "25px" }}>
      <h2>Job Applications (Admin)</h2>

      {apps.length === 0 ? (
        <p>No applications found.</p>
      ) : (
        <table className="designation-table">
          <thead>
            <tr>
              <th>S.No</th>
              <th>Employee</th>
              <th>Email</th>
              <th>Job Title</th>
              <th>Status</th>
              <th>Applied Date</th>
              <th>Action</th>
            </tr>
          </thead>

          <tbody>
            {apps.map((a, index) => {
              const status = a.status || "Pending";

              return (
                <tr key={a.id}>
                  <td>{index + 1}</td>
                  <td>{a.employeeName || a.employee || "Candidate"}</td>
                  <td>{a.email}</td>
                  <td>{a.jobTitle}</td>
                  <td>{status}</td>
                  <td>{a.appliedDate || "--"}</td>

                  <td style={{ display: "flex", gap: "10px" }}>
                    {status === "Pending" && (
                      <>
                        <button
                          className="btn-green"
                          onClick={() => updateStatus(a.id, "Approved")}
                        >
                          Approve
                        </button>

                        <button
                          className="btn-red"
                          onClick={() => updateStatus(a.id, "Rejected")}
                        >
                          Reject
                        </button>
                      </>
                    )}

                    {status === "Approved" && (
                      <button
                        className="btn-green"
                        onClick={() =>
                          navigate(
                            `/dashboard/recruitment/offer-letter/${a.id}`
                          )
                        }
                      >
                        Create Offer
                      </button>
                    )}

                    {status === "Offer Sent" && (
                      <>
                        <button
                          className="btn-blue"
                          onClick={() =>
                            navigate(
                              `/dashboard/recruitment/offer-letter/${a.id}`
                            )
                          }
                        >
                          Edit Offer
                        </button>

                        <button
                          className="btn-gray"
                          onClick={() =>
                            navigate(
                              `/dashboard/recruitment/offer-preview/${a.id}`
                            )
                          }
                        >
                          View Offer
                        </button>
                      </>
                    )}
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      )}
    </div>
  );

  function updateStatus(id, status) {
    const apps =
      JSON.parse(localStorage.getItem("applications")) || [];

    const updated = apps.map((a) =>
      a.id === id ? { ...a, status } : a
    );

    localStorage.setItem("applications", JSON.stringify(updated));
    setApps(updated);
  }
}

export default ViewApplications;
